final:
module top_module (
    input clk,
    input reset,
    output reg [5:0] q
);

    // Fibonacci LFSR logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q <= 6'b000001;
        else
            q <= {q[4:0], q[5] ^ q[4]};
    end

endmodule
